shader:
varying vec2 vUv;
varying vec3 vPosition;
uniform float time;
uniform vec2 resolution;

// Function to generate pseudo-random float
float rand(vec2 co) {
    return fract(sin(dot(co.xy, vec2(12.9898, 78.233))) * 43758.5453);
}

void main() {
    // Base dark space background
    vec3 finalColor = vec3(0.01, 0.01, 0.03);

    // --- Distant Stars ---
    // Scale vPosition for star density across the sphere surface
    vec2 starPos = vPosition.xy * 200.0;
    float starNoise = rand(floor(starPos));
    // Make stars sparse and add a subtle twinkle
    if (starNoise > 0.996) { // Higher threshold for sparser stars
        // Brighter stars with a more noticeable twinkle
        finalColor += vec3(0.8 + 0.2 * sin(time * 5.0 + starNoise * 100.0)) * 0.8;
    }

    // --- Space Station Structure ---
    // vPosition is the 3D coordinate on the sphere [-1, 1]
    // Use it to define geometric patterns that look like a station

    // Calculate angular and radial components relative to the camera's forward view
    float angle = atan(vPosition.y, vPosition.x);
    float radius = length(vPosition.xy); // Distance from the 'pole' (center of screen view)

    // Neon colors for the station, pulsating between two hues
    vec3 neonColorA = vec3(0.0, 0.7, 1.0); // Cyan
    vec3 neonColorB = vec3(1.0, 0.2, 0.8); // Magenta
    vec3 currentNeonColor = mix(neonColorA, neonColorB, 0.5 + 0.5 * sin(time * 0.4));

    // Overall pulsating effect for the neon glow
    float pulse = 1.0 + 0.5 * sin(time * 2.0);

    // --- Rings ---
    // Multiple concentric rings around the central view
    float ringPattern1 = smoothstep(0.0, 0.02, abs(mod(radius * 15.0 + time * 0.1, 1.0) - 0.5));
    float ringPattern2 = smoothstep(0.0, 0.01, abs(radius - 0.7 - sin(time * 0.3) * 0.05)); // Main pulsating ring
    float ringPattern3 = smoothstep(0.0, 0.03, abs(radius * 5.0 - 0.5 - cos(time * 0.2) * 0.1)); // Another offset ring

    float rings = max(ringPattern1, max(ringPattern2, ringPattern3));

    // --- Spokes/Grid Lines ---
    // Radial spokes emanating from the center
    float spokePattern = smoothstep(0.0, 0.015, abs(mod(angle * 10.0 / 3.14159 + time * 0.05, 1.0) - 0.5));

    // Linear grid-like patterns, slightly moving
    float gridPatternX = smoothstep(0.0, 0.01, abs(sin(vPosition.x * 25.0 + time * 0.07)));
    float gridPatternY = smoothstep(0.0, 0.01, abs(cos(vPosition.y * 25.0 - time * 0.07)));
    float gridPatterns = max(gridPatternX, gridPatternY);

    // Combine structure elements
    // Spokes and grid patterns fade out towards the edges (higher radius) to imply depth
    float structureMask = max(rings, spokePattern * (1.0 - radius * 0.5));
    structureMask = max(structureMask, gridPatterns * (1.0 - pow(radius, 2.0))); // Grid fades faster

    // Apply neon glow to the detected structure
    // Boost intensity to create a strong glow effect
    vec3 glowingStructure = currentNeonColor * structureMask * pulse * 3.0;

    // --- Soft Neon Haze/Bloom ---
    // Create a softer, more spread-out glow around the main structure lines
    float hazeIntensity = pow(structureMask, 1.5) * 0.5; // Soften and reduce intensity slightly
    vec3 haze = currentNeonColor * hazeIntensity * pulse;

    // Combine all elements to form the final environment
    finalColor += glowingStructure;
    finalColor += haze;

    // Simple tone mapping/exposure adjustment to enhance the glowing look
    finalColor = pow(finalColor, vec3(0.8)); // Reduce highlights, boost shadows subtly
    finalColor = clamp(finalColor, 0.0, 1.0); // Ensure color stays within valid range

    gl_FragColor = vec4(finalColor, 1.0);
}
